#include <bits/stdc++.h>
using namespace std;
double n,x,h=10,a,ans,cnt,p=1,dead=0;
int main(){
    cin>>n; 
    for(int i=1;i<=n;i++){
        cin>>x>>a;
        if(dead==0){
            h-=x;
            if(h<=0){
                dead=1;
                continue;
            }else if(h>10){
                h=10;
            }
            cnt+=a;
            while(cnt>=p){
                ans++;
                cnt-=p;
                p*=2;
            }
        }
    }
    cout<<ans<<' '<<cnt;
    return 0;
}
